#!/usr/bin/env bash
set -euo pipefail;source "$(dirname "$0")/lib/android-test.sh";serial=emulator-5554;package=org.archphene.linux.p2bb8d769a2318af9bf9b60a9f8b7ec5f;activity=org.archphene.linux.kcalc.MainActivity;pack=;action=Both;timeout=120;while (($#));do case "$1" in --serial)serial="${2:?}";shift 2;;--package)package="${2:?}";shift 2;;--activity)activity="${2:?}";shift 2;;--runtime-pack-id)pack="${2:?}";shift 2;;--permission-action)action="${2:?}";shift 2;;--startup-timeout-seconds)timeout="${2:?}";shift 2;;*)archphene_die "unknown argument: $1";;esac;done;[[ "$pack" =~ ^[0-9a-f]{64}$ ]] || archphene_die '--runtime-pack-id must be 64 lowercase hex characters';archphene_validate_choice "$action" action Grant Deny Both;archphene_test_init "$serial";manager=org.archpheneos.manager;archphene_adb_run shell am start -W -n "$manager/.MainActivity" --ez archphene_test_package_runtime true --es archphene_test_bind_pack "$pack" --es archphene_test_bind_package "$package" >/dev/null;actions=($action);[[ "$action" == Both ]] && actions=(Grant Deny);for choice in "${actions[@]}";do archphene_adb_run shell pm revoke "$package" android.permission.CAMERA >/dev/null 2>&1 || true;archphene_adb_run logcat -c;archphene_adb_run shell am start -W -n "$package/$activity" --ez archphene_test_media_debug true >/dev/null;archphene_wait_ui_text Camera generated-camera "$timeout";ui="$ARCHPHENE_UI";if [[ "$choice" == Grant ]];then for text in 'While using the app' 'Only this time' Allow;do if [[ "$ui" == *"$text"* ]];then archphene_tap_text "$ui" "$text";break;fi;done;archphene_wait_log 'PipeWire|camera frame' 30 'ArchpheneRuntime ArchpheneCamera AndroidRuntime *:S' >/dev/null;else for text in "Don't allow" Deny;do if [[ "$ui" == *"$text"* ]];then archphene_tap_text "$ui" "$text";break;fi;done;archphene_wait_log 'denied|permission' 30 'ArchpheneRuntime ArchpheneCamera AndroidRuntime *:S' >/dev/null;fi;archphene_note "Generated camera app $choice path passed on $serial";done;archphene_note "Generated unmodified camera consumer passed on $serial: ${actions[*]} permission paths."
